import{_ as t,o as e,c as a,ak as _}from"./chunks/framework.DwgkYvd1.js";const m=JSON.parse('{"title":"7月24日","description":"","frontmatter":{"title":"7月24日","date":"2021-07-24T18:59:32.000Z","tags":null},"headers":[],"relativePath":"诗与散文/7月24日.md","filePath":"诗与散文/7月24日.md"}'),r={name:"诗与散文/7月24日.md"};function o(s,p,n,c,d,i){return e(),a("div",null,[...p[0]||(p[0]=[_("<p>无言的告别</p><p>悄悄地离开</p><p>背对整个世界</p><p>想必你早知道</p><p>我已厌倦多余的存在</p><p>夜夜新生</p><p>始自雨中大巴的低鸣</p><p>区区终了</p><p>抬头面对满目的热烈</p><p>头紧靠在车玻璃</p><p>凝视夜行的树向后逃离</p><p>吸气呼气交替</p><p>车窗明暗相迷</p><p>掩泣扑朔的街灯</p><p>以祭梦中的笑声</p><p>入耳你说过的每一句</p><p>如今却在泪中学着忘记</p><p>小心翼翼回忆往昔</p><p>每次都像望见血色的鎏金</p><p>在梦中摸索期许的自己</p><p>却翻找出过去的记忆</p><p>你的名字镌刻在其里</p><p>久久消磨不掉痕迹</p><p>我走了，曾经的朋友</p><p>等你感知我离开</p><p>我亦不会回头</p><p>不复无悔的想你走来</p><p>拐角处的回眸</p><p>已不抱任何期待</p><p>唯江边夜风拂面下</p><p>回望空荡离世尘喧嚣</p><p>犹惶惶不安得所</p>",32)])])}const f=t(r,[["render",o]]);export{m as __pageData,f as default};
